 1	import React, { FC } from 'react';
 2	
 3	import { ResourceYAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
 4	import { PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 5	import { EditorType } from '@utils/components/SyncedEditor/EditorToggle';
 6	import { SyncedEditor } from '@utils/components/SyncedEditor/SyncedEditor';
 7	import { safeYAMLToJS } from '@utils/components/SyncedEditor/yaml';
 8	import { NET_ATTACH_DEF_HEADER_LABEL } from '@utils/constants';
 9	import { LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY } from '@views/networkpolicies/new/utils/const';
10	
11	import { generateDefaultNAD } from './utils/constants';
12	import NetworkAttachmentDefinitionForm from './NetworkAttachmentDefinitionForm';
13	
14	const NetworkAttachmentDefinitionFormPage: FC = () => (
15	  <>
16	    <PageSection variant={PageSectionVariants.light}>
17	      <Title headingLevel="h1">{NET_ATTACH_DEF_HEADER_LABEL}</Title>
18	    </PageSection>
19	    <SyncedEditor
20	      displayConversionError
21	      FormEditor={NetworkAttachmentDefinitionForm}
22	      initialData={generateDefaultNAD()}
23	      initialType={EditorType.Form}
24	      lastViewUserSettingKey={LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY}
25	      YAMLEditor={({ initialYAML = '', onChange }) => (
26	        <ResourceYAMLEditor
27	          create
28	          hideHeader
29	          initialResource={safeYAMLToJS(initialYAML)}
30	          onChange={onChange}
31	        />
32	      )}
33	    />
34	  </>
35	);
36	
37	export default NetworkAttachmentDefinitionFormPage;

